FUNCTION Map_External_To_Conceptual(userQuery)
  BEGIN
    // Step 1: Parse external schema view
    externalView = GET_USER_VIEW(userQuery.userID)

    // Step 2: Map attributes to conceptual schema
    mappedAttributes = MAP_ATTRIBUTES(
      userQuery.attributes,
      externalView.attributeMapping
    )

    // Step 3: Transform predicates
    mappedPredicate = MAP_PREDICATE(
      userQuery.condition,
      externalView.predicateMapping
    )

    // Step 4: Generate conceptual query
    conceptualQuery = BUILD_QUERY(
      mappedAttributes,
      mappedPredicate,
      "Enrollment, Student, Course"
    )

    RETURN conceptualQuery
  END

class ConceptualToInternalMapper:
    """Maps conceptual queries to internal physical execution plans"""

    def __init__(self):
        self.index_info = {
            'student_id': 'BTree_index',
            'course_id': 'Hash_index',
            'enrollment_date': 'BTree_index'
        }
        self.storage_info = {
            'students': 'sequential_file',
            'courses': 'clustered_file',
            'enrollment': 'heap_file'
        }

    def map_to_internal(self, conceptual_query):
        """Transform conceptual query to physical execution plan"""

        # Step 1: Identify tables involved
        tables = conceptual_query.get('tables', [])

        # Step 2: Select optimal access path
        access_paths = []
        for table in tables:
            storage = self.storage_info.get(table, 'heap_file')

            # Check for usable indexes
            indexes = []
            for field in conceptual_query.get('conditions', []):
                if field in self.index_info:
                    indexes.append(self.index_info[field])

            access_paths.append({
                'table': table,
                'storage': storage,
                'indexes': indexes,
                'access_method': 'index_scan' if indexes else 'full_scan'
            })

        # Step 3: Generate physical execution plan
        return {
            'execution_plan': access_paths,
            'estimated_cost': self.calculate_cost(access_paths)
        }

    def calculate_cost(self, access_paths):
        """Estimate query execution cost"""
        cost = 0
        for path in access_paths:
            if path['access_method'] == 'index_scan':
                cost += 10  # Lower cost with index
            else:
                cost += 100  # Full table scan
        return cost

